const trips = $input.first().json.result || [];
const idleVehicles = [];

function parseMins(dur) {
  if (!dur) return 0;
  const hms = String(dur).match(/^(\d+):(\d+):(\d+(?:\.\d+)?)$/);
  if (hms) return parseInt(hms[1]||0)*60 + parseInt(hms[2]||0) + parseFloat(hms[3]||0)/60;
  const pt = String(dur).match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+(?:\.\d+)?)S)?/);
  if (pt) return parseInt(pt[1]||0)*60 + parseInt(pt[2]||0) + parseFloat(pt[3]||0)/60;
  return 0;
}

for (const trip of trips) {
  const mins = parseMins(trip.idlingDuration);
  if (mins > 30) {
    idleVehicles.push({ device: trip.device?.id, idleMinutes: Math.round(mins), distance: (trip.distance||0).toFixed(1) });
  }
}
return [{ json: { idleVehicles, count: idleVehicles.length } }];
